  }

  process(data) {
    // FIX: Use .once() to ensure listeners are removed after firing
    this.eventBus.once('data:validated', (validatedData) => {
      this._handleValidated(validatedData, data);
    });

    this.eventBus.once('data:error', (err) => {
      console.error(`Processing error for batch ${this.processedCount}: ${err.message}`);
    });
